def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 0
        bonus = 0
        for j in range(1, 8):
            threshold = j * 0.15
            if ratio < threshold:
                increment = (8 - j) * np.log1p(capacity) * (1 + np.sin(j))
                score += increment
                if j % 2 == 0:
                    bonus += np.sqrt(capacity) / (j + 1)
                else:
                    bonus += np.log1p(item) / (j + 1)
            else:
                decrement = j * np.sqrt(item) * (1 + np.cos(j))
                penalty += decrement
        score = score + bonus - penalty
        if capacity < item * 1.2:
            score *= 1.7
        elif capacity < item * 2:
            score *= 1.3
        elif capacity > item * 4:
            score /= 2.5
        elif capacity > item * 3:
            score /= 1.8
        if ratio > 0.8:
            for k in range(3):
                score += np.log1p(capacity) / (k + 1) - np.sqrt(item) * (k + 1)
        if score < 0:
            score = np.abs(score) / 2
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 15
    return priorities
